import React, { useRef, useEffect } from 'react';

const CUSTOM_ASSETS: Record<string, string> = {
  anomaly: "", // Otonom Anomali / Veri Düğümü (Şeffaf PNG 3D Objesi için)
  guide:   "data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI2NCIgaGVpZ2h0PSI2NCIgdmlld0JveD0iMCAwIDY0IDY0Ij48Y2lyY2xlIGN4PSIzMiIgY3k9IjMyIiByPSIyOCIgZmlsbD0iIzAwZmZmZiIvPjxwYXRoIGQ9Ik0yNCAzMmgxNm0tOC04djE2IiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iNCIvPjwvc3ZnPg==" // Mavi Rehber Düğüm
};

// Props
interface LabyrinthProps {
  level: number;
  onAtDoor: (doorId: string, itemType: 'terminal' | 'gateway' | 'anomaly') => void;
  openDoors: string[];
  isQuestionOpen: boolean;
  onActionPrompt: (show: boolean, interactionType?: string) => void;
}

export function Labyrinth({ level, onAtDoor, openDoors, isQuestionOpen, onActionPrompt }: LabyrinthProps) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    
    // Oyun durumu ref'te tutulur (Closure sorunlarını önlemek için)
    const gameState = useRef({
        posX: 2.5,
        posY: 2.5,
        dirX: 1.0,
        dirY: 0.0,
        planeX: 0.0,
        planeY: 0.66,
        keys: { w: false, s: false, a: false, d: false, e: false },
        joyMove: 0,
        joyTurn: 0,
        mouseTurn: 0,
        targetDoor: null as {x: number, y: number, type: 'terminal' | 'gateway' | 'anomaly'} | null,
        worldMap: [] as number[][],
        sprites: [] as { x: number, y: number, type: string, color: string, vx?: number, vy?: number }[],
        images: {} as Record<string, HTMLImageElement>,
        bobPhase: 0,
        pitch: 0,
        mapSize: 15,
    });
    
    // Modalı (soruyu) duraklatmak için referanslar
    const isPausedRef = useRef(isQuestionOpen);
    useEffect(() => {
        isPausedRef.current = isQuestionOpen;
    }, [isQuestionOpen]);
    
    const openDoorsRef = useRef(openDoors);
    useEffect(() => {
        openDoorsRef.current = openDoors;
    }, [openDoors]);

    // Harita ve varlıkları oluştur (Sadece bir kez veya level değiştiğinde)
    useEffect(() => {
        const gs = gameState.current;
        
        // Görüntüleri Yükle
        const getAssetSrc = (src: string) => src.startsWith('data:image') ? src : `data:image/png;base64,${src}`;
        Object.entries(CUSTOM_ASSETS).forEach(([key, src]) => {
            const finalSrc = getAssetSrc(src);
            if (finalSrc) {
                const img = new Image();
                img.src = finalSrc;
                gs.images[key] = img;
            }
        });

        const currentMapSize = 15 + (level * 5);
        gs.mapSize = currentMapSize;

        const newMap = Array(currentMapSize).fill(0).map(() => Array(currentMapSize).fill(1));
        const newSprites: { x: number, y: number, type: string, color: string }[] = [];

        // DFS Maze Carving
        const carveDir = [ [0, -1], [0, 1], [-1, 0], [1, 0] ];
        const carve = (cx: number, cy: number) => {
            newMap[cx][cy] = 0;
            const dirs = [...carveDir].sort(() => Math.random() - 0.5);
            for (const [dx, dy] of dirs) {
                const nx = cx + dx * 2;
                const ny = cy + dy * 2;
                if (nx > 0 && nx < currentMapSize - 1 && ny > 0 && ny < currentMapSize - 1 && newMap[nx][ny] === 1) {
                    newMap[cx + dx][cy + dy] = 0; // Duvarı yık
                    carve(nx, ny); // İleri git
                }
            }
        };
        
        carve(1, 1);

        // Labirenti biraz daha açık hale getirmek için ekstra duvar kır
        for (let x = 1; x < currentMapSize - 1; x++) {
            for (let y = 1; y < currentMapSize - 1; y++) {
                if (newMap[x][y] === 1 && Math.random() > 0.85) {
                    newMap[x][y] = 0;
                }
            }
        }
        
        // Sınırları kapat
        for (let i = 0; i < currentMapSize; i++) {
            newMap[0][i] = 1; newMap[currentMapSize - 1][i] = 1;
            newMap[i][0] = 1; newMap[i][currentMapSize - 1] = 1;
        }

        // Güvenli Oda (Başlangıç)
        gs.posX = 2.5; gs.posY = 2.5;
        newMap[1][1] = 0; newMap[1][2] = 0; newMap[2][1] = 0; newMap[2][2] = 0;

        // BFS ile tüm noktaların başlangıca uzaklığını bul
        let queue = [{x: 2, y: 2, dist: 0}];
        let distances = Array(currentMapSize).fill(0).map(() => Array(currentMapSize).fill(-1));
        distances[2][2] = 0;
        let allNodes: {x: number, y: number, dist: number}[] = [];

        while(queue.length > 0) {
            let curr = queue.shift()!;
            allNodes.push(curr);
            for (const [dx, dy] of carveDir) {
                let nx = curr.x + dx;
                let ny = curr.y + dy;
                // Sınırlar içinde kontrol ediyoruz
                if (nx > 0 && nx < currentMapSize - 1 && ny > 0 && ny < currentMapSize - 1 && newMap[nx][ny] === 0 && distances[nx][ny] === -1) {
                    distances[nx][ny] = curr.dist + 1;
                    queue.push({x: nx, y: ny, dist: curr.dist + 1});
                }
            }
        }

        // Node'ları uzaklığa göre sırala (en uzaklar başta)
        allNodes.sort((a, b) => b.dist - a.dist);

        // En uzak noktaya Ana Ağ Geçidi (2)
        const gatewayNode = allNodes.shift()!;
        newMap[gatewayNode.x][gatewayNode.y] = 2; // Ana Ağ Geçidi
        
        // En uzaktaki diğer 3 noktaya Güvenli Veri Odası Terminali (3)
        let terminalsPlaced = 0;
        let minRadius = 5;
        let placedPoints = [gatewayNode];
        
        for (let i = 0; i < allNodes.length && terminalsPlaced < 3; i++) {
            const cand = allNodes[i];
            let tooClose = false;
            for (const pt of placedPoints) {
                const dist = Math.sqrt((cand.x - pt.x) ** 2 + (cand.y - pt.y) ** 2);
                if (dist < minRadius) { tooClose = true; break; }
            }
            if (!tooClose) {
                newMap[cand.x][cand.y] = 3; // Veri Terminali
                placedPoints.push(cand);
                terminalsPlaced++;
            }
        }

        // Eğer mesafe kısıtlamasından dolayı 3 tane konulamadıysa, kalanları doğrudan koy
        while(terminalsPlaced < 3 && allNodes.length > 0) {
            const cand = allNodes.pop()!;
            if (newMap[cand.x][cand.y] === 0) {
                newMap[cand.x][cand.y] = 3;
                terminalsPlaced++;
            }
        }

        // Otonom Varlıklar (Anomaliler)
        const emptyCells = allNodes.filter(n => newMap[n.x][n.y] === 0 && (n.x > 3 || n.y > 3));
        emptyCells.sort(() => Math.random() - 0.5);
        for (let i = 0; i < 4 + level && i < emptyCells.length; i++) {
            newSprites.push({ x: emptyCells[i].x + 0.5, y: emptyCells[i].y + 0.5, type: 'anomaly', color: '#ff00ff' });
        }
        
        // Statik Rehber / NPC
        newSprites.push({ x: 2.5, y: 3.5, type: 'guide', color: '#00ffff' });

        gs.worldMap = newMap;
        gs.sprites = newSprites;
    }, [level]);
    
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        
        let reqId: number;
        
        const moveSpeed = 0.05;
        const rotSpeed = 0.04;

        // Doku Üretimi (Procedural Textures)
        const TEX_SIZE = 64;
        const texMap: Record<number, HTMLCanvasElement> = {
            1: document.createElement('canvas'),
            2: document.createElement('canvas'),
            3: document.createElement('canvas') // Terminal Odası Duvarı
        };
        texMap[1].width = TEX_SIZE; texMap[1].height = TEX_SIZE;
        texMap[2].width = TEX_SIZE; texMap[2].height = TEX_SIZE;
        texMap[3].width = TEX_SIZE; texMap[3].height = TEX_SIZE;
        
        const ctxW = texMap[1].getContext('2d');
        if (ctxW) {
            ctxW.fillStyle = '#0F172A';
            ctxW.fillRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxW.strokeStyle = '#00ffff';
            ctxW.lineWidth = 2;
            ctxW.strokeRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxW.beginPath();
            for (let i = 8; i < TEX_SIZE; i += 16) {
                ctxW.moveTo(0, i); ctxW.lineTo(TEX_SIZE, i);
            }
            ctxW.stroke();
            ctxW.fillStyle = 'rgba(0, 255, 255, 0.5)';
            ctxW.fillRect(10, 10, 4, 4);
            ctxW.fillRect(30, 40, 4, 4);
        }

        const ctxD = texMap[2].getContext('2d');
        if (ctxD) {
            ctxD.fillStyle = '#1e051e';
            ctxD.fillRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxD.strokeStyle = '#ff00ff';
            ctxD.lineWidth = 4;
            ctxD.strokeRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxD.beginPath();
            ctxD.moveTo(TEX_SIZE / 2, 0); ctxD.lineTo(TEX_SIZE / 2, TEX_SIZE);
            ctxD.moveTo(0, TEX_SIZE / 2); ctxD.lineTo(TEX_SIZE, TEX_SIZE / 2);
            ctxD.stroke();
            ctxD.fillStyle = '#ff00ff';
            ctxD.fillRect(TEX_SIZE / 2 - 6, TEX_SIZE / 2 - 10, 12, 20);
        }

        const ctxT = texMap[3].getContext('2d');
        if (ctxT) {
            ctxT.fillStyle = '#0a1a0a';
            ctxT.fillRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxT.strokeStyle = '#32cd32';
            ctxT.lineWidth = 3;
            ctxT.strokeRect(0, 0, TEX_SIZE, TEX_SIZE);
            ctxT.beginPath();
            ctxT.arc(TEX_SIZE / 2, TEX_SIZE / 2, 8, 0, Math.PI * 2);
            ctxT.stroke();
            ctxT.fillStyle = '#32cd32';
            ctxT.fillRect(TEX_SIZE / 2 - 2, TEX_SIZE / 2 - 2, 4, 4);
        }
        
        // Klavye Kontrolleri
        const handleKeyDown = (e: KeyboardEvent) => {
            const k = e.key.toLowerCase();
            const gsKeys = gameState.current.keys;
            if (k === 'w' || k === 'arrowup') gsKeys.w = true;
            if (k === 's' || k === 'arrowdown') gsKeys.s = true;
            if (k === 'a' || k === 'arrowleft') gsKeys.a = true;
            if (k === 'd' || k === 'arrowright') gsKeys.d = true;
            if (k === 'e') gsKeys.e = true;
        };
        
        const handleKeyUp = (e: KeyboardEvent) => {
            const k = e.key.toLowerCase();
            const gsKeys = gameState.current.keys;
            if (k === 'w' || k === 'arrowup') gsKeys.w = false;
            if (k === 's' || k === 'arrowdown') gsKeys.s = false;
            if (k === 'a' || k === 'arrowleft') gsKeys.a = false;
            if (k === 'd' || k === 'arrowright') gsKeys.d = false;
            if (k === 'e') gsKeys.e = false;
        };

        // Mouse Kontrolleri
        const handleCanvasClick = () => {
            if (!isPausedRef.current && canvas) {
                canvas.requestPointerLock();
            }
        };
        const handleMouseMove = (e: MouseEvent) => {
            if (document.pointerLockElement === canvas && !isPausedRef.current) {
                // Hassasiyeti ayarlamak için 0.002 çarpanı
                gameState.current.mouseTurn -= e.movementX * 0.002;
            }
        };
        
        canvas.addEventListener('click', handleCanvasClick);
        window.addEventListener('mousemove', handleMouseMove);
        
        window.addEventListener('keydown', handleKeyDown);
        window.addEventListener('keyup', handleKeyUp);
        
        // Dinamik harita (açılan kapıları hava (0) olarak gösterir)
        const getMapData = (x: number, y: number) => {
            const ms = gameState.current.mapSize;
            if (x < 0 || x >= ms || y < 0 || y >= ms) return 1; // Sınır dışı duvar
            const worldMap = gameState.current.worldMap;
            if (!worldMap || worldMap.length === 0) return 1;

            const cell = worldMap[x][y];
            if ((cell === 2 || cell === 3) && openDoorsRef.current.includes(`${x},${y}`)) {
                return 0; // Kapı açılmış, geçiş serbest
            }
            return cell;
        };
        
        let lastPromptState = false;

        const updateSprites = (gs: typeof gameState.current) => {
            let hitAnomalyIndex = -1;
            gs.sprites.forEach((sprite, index) => {
                if (sprite.type === 'anomaly') {
                    // Rastgele hareket (Random movement)
                    if (sprite.vx === undefined || sprite.vy === undefined) {
                        const angle = Math.random() * Math.PI * 2;
                        sprite.vx = Math.cos(angle) * 0.02;
                        sprite.vy = Math.sin(angle) * 0.02;
                    }
                    // Arada bir yön değiştir (Change direction randomly sometimes)
                    if (Math.random() < 0.05 && !isPausedRef.current) {
                        const angle = Math.random() * Math.PI * 2;
                        sprite.vx = Math.cos(angle) * 0.02;
                        sprite.vy = Math.sin(angle) * 0.02;
                    }
                    
                    if (!isPausedRef.current) {
                        const nextX = sprite.x + (sprite.vx || 0);
                        const nextY = sprite.y + (sprite.vy || 0);
                        
                        if (getMapData(Math.floor(nextX), Math.floor(sprite.y)) === 0) {
                            sprite.x = nextX;
                        } else {
                            sprite.vx = -(sprite.vx || 0);
                        }
                        
                        if (getMapData(Math.floor(sprite.x), Math.floor(nextY)) === 0) {
                            sprite.y = nextY;
                        } else {
                            sprite.vy = -(sprite.vy || 0);
                        }
                    }

                    // Sadece Veri Parçacığı ile temas mesafesi hesapla
                    let dx = gs.posX - sprite.x;
                    let dy = gs.posY - sprite.y;
                    let dist = Math.sqrt(dx*dx + dy*dy);
                    
                    if (dist <= 0.6 && !isPausedRef.current) {
                        // Veri parçacığı oyuncuya temas ettiğinde anlık prosedür doğrulaması tetikler.
                        hitAnomalyIndex = index;
                    }
                }
            });

            if (hitAnomalyIndex !== -1) {
                gs.sprites.splice(hitAnomalyIndex, 1);
                // Anomali/veri alındığında onAtDoor üzerinden soru açılabilir veya senaryoya iletilebilir
                onAtDoor(`scrap_${Date.now()}`, 'anomaly');
            }
        };

        const update = () => {
            if (isPausedRef.current) return;
            
            const gs = gameState.current;
            
            // İleri - Geri yürüme (Çarpışma algılama - Wall Sliding)
            let moved = false;
            let moveVel = 0;
            let strafeVel = 0;

            if (gs.keys.w) moveVel += moveSpeed;
            if (gs.keys.s) moveVel -= moveSpeed;
            if (gs.keys.d) strafeVel += moveSpeed;
            if (gs.keys.a) strafeVel -= moveSpeed;
            moveVel += gs.joyMove * moveSpeed;

            if (moveVel !== 0 || strafeVel !== 0) {
                // Combine movement vectors
                let finalMoveX = gs.dirX * moveVel + gs.planeX * strafeVel;
                let finalMoveY = gs.dirY * moveVel + gs.planeY * strafeVel;

                // Normalize if pressing two keys so we don't move faster diagonally
                const length = Math.sqrt(finalMoveX * finalMoveX + finalMoveY * finalMoveY);
                if (length > moveSpeed) {
                    finalMoveX = (finalMoveX / length) * moveSpeed;
                    finalMoveY = (finalMoveY / length) * moveSpeed;
                }

                if (getMapData(Math.floor(gs.posX + finalMoveX), Math.floor(gs.posY)) === 0) {
                    gs.posX += finalMoveX;
                    moved = true;
                }
                if (getMapData(Math.floor(gs.posX), Math.floor(gs.posY + finalMoveY)) === 0) {
                    gs.posY += finalMoveY;
                    moved = true;
                }
            }

            // Yürüme Hissi (Head Bobbing)
            if (moved) {
                gs.bobPhase += 0.25;
            } else if (gs.bobPhase > 0) {
                const remainder = gs.bobPhase % (Math.PI * 2);
                if (remainder > 0.1 && remainder < Math.PI * 2 - 0.1) {
                    gs.bobPhase += 0.1;
                } else {
                    gs.bobPhase = 0;
                }
            }
            gs.pitch = Math.sin(gs.bobPhase) * 10;
            
            // Sağa - Sola Dönüş (Vektör Rotasyonu)
            let turnActive = 0;
            turnActive += gs.joyTurn * rotSpeed;

            // Mouse yörünge
            turnActive += gs.mouseTurn;
            gs.mouseTurn = 0; // tüket

            if (turnActive !== 0) {
                const oldDirX = gs.dirX;
                gs.dirX = gs.dirX * Math.cos(turnActive) - gs.dirY * Math.sin(turnActive);
                gs.dirY = oldDirX * Math.sin(turnActive) + gs.dirY * Math.cos(turnActive);
                const oldPlaneX = gs.planeX;
                gs.planeX = gs.planeX * Math.cos(turnActive) - gs.planeY * Math.sin(turnActive);
                gs.planeY = oldPlaneX * Math.sin(turnActive) + gs.planeY * Math.cos(turnActive);
            }
            
            updateSprites(gs);

            // Kapı Yakınlık Kontrolü (Proximity Check) - Gelişmiş menzil
            let nearDoor = false;
            const dists = [0.5, 1.0, 1.5]; // İleriye doğru 3 noktayı kontrol et
            
            for (let dist of dists) {
                let lookX = Math.floor(gs.posX + gs.dirX * dist);
                let lookY = Math.floor(gs.posY + gs.dirY * dist);
                
                const ms = gs.mapSize;
                if (lookX >= 0 && lookX < ms && lookY >= 0 && lookY < ms) {
                    const cell = getMapData(lookX, lookY);
                    if (cell === 2 || cell === 3) {
                        nearDoor = true;
                        gs.targetDoor = {x: lookX, y: lookY, type: cell === 2 ? 'gateway' : 'terminal'};
                        break;
                    }
                }
            }
            
            if (!nearDoor) gs.targetDoor = null;

            // Etkileşim: E tuşu veya Aksiyon düğmesi
            if (gs.keys.e && gs.targetDoor && !isPausedRef.current) {
                onAtDoor(`${gs.targetDoor.x},${gs.targetDoor.y}`, gs.targetDoor.type);
                gs.keys.e = false; // Tek bir kez tetiklemek için tüket
            }

            // Prompt aksiyonu - debounce yapısı
            const shouldPrompt = gs.targetDoor !== null;
             if (shouldPrompt !== lastPromptState) {
                lastPromptState = shouldPrompt;
                setTimeout(() => onActionPrompt(shouldPrompt, gs.targetDoor?.type), 0);
             }
        };

        const draw = () => {
            const screenW = canvas.width;
            const screenH = canvas.height;
            const gs = gameState.current;

            // Zemin ve Tavan
            const horizon = Math.floor(screenH / 2 + gs.pitch);
            ctx.fillStyle = '#05050A'; // Retrowave tavan
            ctx.fillRect(0, 0, screenW, horizon);
            ctx.fillStyle = '#0A0A10'; // Zemin
            ctx.fillRect(0, horizon, screenW, screenH - horizon);

            let zBuffer = new Array(screenW).fill(0);

            // DDA Algoritması (Duvarlar)
            for (let x = 0; x < screenW; x++) {
                const cameraX = 2 * x / screenW - 1;
                const rayDirX = gs.dirX + gs.planeX * cameraX;
                const rayDirY = gs.dirY + gs.planeY * cameraX;

                let mapX = Math.floor(gs.posX);
                let mapY = Math.floor(gs.posY);

                let sideDistX, sideDistY;
                const deltaDistX = Math.abs(1 / rayDirX);
                const deltaDistY = Math.abs(1 / rayDirY);
                let perpWallDist;

                let stepX, stepY;
                let hit = 0, side = 0;

                if (rayDirX < 0) { stepX = -1; sideDistX = (gs.posX - mapX) * deltaDistX; } 
                else { stepX = 1; sideDistX = (mapX + 1.0 - gs.posX) * deltaDistX; }
                if (rayDirY < 0) { stepY = -1; sideDistY = (gs.posY - mapY) * deltaDistY; } 
                else { stepY = 1; sideDistY = (mapY + 1.0 - gs.posY) * deltaDistY; }

                while (hit === 0) {
                    if (sideDistX < sideDistY) { sideDistX += deltaDistX; mapX += stepX; side = 0; } 
                    else { sideDistY += deltaDistY; mapY += stepY; side = 1; }
                    hit = getMapData(mapX, mapY);
                }

                if (side === 0) perpWallDist = (sideDistX - deltaDistX);
                else perpWallDist = (sideDistY - deltaDistY);

                zBuffer[x] = perpWallDist; // Spreytler için z-buffer

                const lineHeight = Math.floor(screenH / perpWallDist);
                let drawStart = -lineHeight / 2 + screenH / 2 + gs.pitch;
                let drawEnd = lineHeight / 2 + screenH / 2 + gs.pitch;

                // Doku hesaplama (Texture Mapping)
                let wallX;
                if (side === 0) wallX = gs.posY + perpWallDist * rayDirY;
                else wallX = gs.posX + perpWallDist * rayDirX;
                wallX -= Math.floor(wallX);

                let texX = Math.floor(wallX * TEX_SIZE);
                if (side === 0 && rayDirX > 0) texX = TEX_SIZE - texX - 1;
                if (side === 1 && rayDirY < 0) texX = TEX_SIZE - texX - 1;

                const textureCanvas = hit === 1 ? texMap[1] : (hit === 3 ? texMap[3] : texMap[2]);

                let sliceY = 0;
                let sliceH = TEX_SIZE;
                let drwStartY = drawStart;
                let drwH = lineHeight;

                if (drawStart < 0) {
                    const overCut = -drawStart;
                    sliceY = (overCut / lineHeight) * TEX_SIZE;
                    sliceH = TEX_SIZE - sliceY;
                    drwStartY = 0;
                    drwH = drawEnd;
                }
                if (drawEnd >= screenH) {
                    const overCut = drawEnd - screenH + 1;
                    const cropHRatio = overCut / lineHeight;
                    sliceH -= cropHRatio * TEX_SIZE;
                    drwH = screenH - Math.max(0, drawStart);
                }

                if (sliceH > 0 && drwH > 0 && sliceY < TEX_SIZE) {
                    ctx.drawImage(
                        textureCanvas,
                        texX, sliceY, 1, sliceH,
                        x, Math.floor(drwStartY), 1, Math.floor(drwH)
                    );
                }

                // Uzaklığa göre Fog/Depth efekti ve Gölgelendirme
                const fog = Math.max(0, Math.min(1, perpWallDist / 12));
                const shadeAlpha = side === 1 ? 0.4 : 0;
                
                ctx.fillStyle = `rgba(0, 0, 0, ${Math.max(fog, shadeAlpha)})`;
                if (Math.floor(drwH) > 0) {
                    ctx.fillRect(x, Math.floor(drwStartY), 1, Math.floor(drwH));
                }
            }

            // Otonom Varlık (Sprite) Çizimi (Raycasting & Billboarding)
            const sortedSprites = gs.sprites.map(s => {
                return { ...s, distance: ((gs.posX - s.x) * (gs.posX - s.x) + (gs.posY - s.y) * (gs.posY - s.y)) };
            }).sort((a, b) => b.distance - a.distance);

            for (let i = 0; i < sortedSprites.length; i++) {
                const sprite = sortedSprites[i];
                const spriteX = sprite.x - gs.posX;
                const spriteY = sprite.y - gs.posY;

                // TERS MATRİS (Inverse Matrix) ile Kusursuz Yönelim
                // Kameraya her zaman dik (cepheden) bakmasını sağlar. Görseller yamulmaz veya basık çizilmez.
                const invDet = 1.0 / (gs.planeX * gs.dirY - gs.dirX * gs.planeY);
                const transformX = invDet * (gs.dirY * spriteX - gs.dirX * spriteY);
                const transformY = invDet * (-gs.planeY * spriteX + gs.planeX * spriteY);

                if (transformY > 0) {
                    const spriteScreenX = Math.floor((screenW / 2) * (1 + transformX / transformY));
                    
                    const renderScale = sprite.type === 'anomaly' ? 0.25 : 1.0;
                    
                    let bobOffset = 0;
                    if (sprite.type === 'anomaly') {
                        const time = Date.now() / 400;
                        bobOffset = Math.sin(time + sprite.x * 10) * (screenH / 20) / Math.max(1, transformY * 0.5);
                    }
                    
                    // Uzaklığa (transformY) göre dinamik ölçekleme (Boy)
                    const spriteHeight = Math.abs(Math.floor(screenH / transformY)) * renderScale;
                    // Eğer küçültülmüşse (renderScale < 1) dikey olarak tam ortada hafif havada (veya aşağıda) durması için
                    // Normalde objeler yerde dursun diye hesaplanır, ama anomali havada süzülebilir.
                    // Orta noktayı merkez alıyoruz. Ekstra bob eklenebilir.
                    let drawStartY = -spriteHeight / 2 + screenH / 2 + gs.pitch + bobOffset;
                    if (drawStartY < 0) drawStartY = 0;
                    let drawEndY = spriteHeight / 2 + screenH / 2 + gs.pitch + bobOffset;
                    if (drawEndY >= screenH) drawEndY = screenH - 1;

                    // Uzaklığa (transformY) göre dinamik ölçekleme (En)
                    const spriteWidth = Math.abs(Math.floor(screenH / transformY)) * renderScale;
                    let drawStartXRaw = -spriteWidth / 2 + spriteScreenX;
                    let drawStartX = Math.max(0, drawStartXRaw);
                    
                    let drawEndXRaw = spriteWidth / 2 + spriteScreenX;
                    let drawEndX = Math.min(screenW - 1, drawEndXRaw);

                    const fog = Math.max(0.1, 1 - (transformY / 12));
                    ctx.globalAlpha = fog;

                    const img = gs.images[sprite.type];
                    const zCheckX = Math.max(0, Math.min(screenW - 1, Math.floor(spriteScreenX)));
                    
                    // Base64 doğrulaması ve yükleme kontrolü
                    if (img && img.complete && img.naturalWidth > 0) {
                        // Tam Sprite Billboarding: Otonom Anomali'nin ortası duvardan öndeyse (zBuffer kontrolü), tam olarak çiz.
                        // Çizgisel parçalama (stripe-render) kullanılmaz; bu sayede şeffaf PNG'ler yüksek kalitede, pürüzsüz çizilir.
                        if (transformY > 0 && transformY < zBuffer[zCheckX] && drawStartXRaw < screenW && drawEndXRaw > 0) {
                            ctx.drawImage(
                                img, 
                                drawStartXRaw, 
                                -spriteHeight / 2 + screenH / 2 + gs.pitch + bobOffset, 
                                spriteWidth, 
                                spriteHeight
                            );
                        }
                    } else {
                        // Varsayılan / Fallback Düz Renk Çizimi (Yüklenmemiş görseller için)
                        ctx.fillStyle = sprite.color;
                        for (let stripe = Math.floor(drawStartX); stripe < drawEndX; stripe++) {
                            if (transformY > 0 && stripe > 0 && stripe < screenW && transformY < zBuffer[stripe]) {
                                ctx.fillRect(stripe, Math.floor(drawStartY), 1, Math.floor(drawEndY - drawStartY));
                            }
                        }
                    }
                    
                    ctx.globalAlpha = 1.0;
                }
            }

            drawMinimap(ctx, screenW, screenH, gs);
        };
        
        const drawMinimap = (ctx: CanvasRenderingContext2D, screenW: number, screenH: number, gs: any) => {
            const mmSize = 120;
            const mmX = screenW - mmSize - 20;
            const mmY = 20; // Sağ üstte dursun
            const cellSize = mmSize / gs.mapSize;

            // Arka plan
            ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
            ctx.fillRect(mmX, mmY, mmSize, mmSize);
            ctx.strokeStyle = '#00ffff';
            ctx.lineWidth = 1;
            ctx.strokeRect(mmX, mmY, mmSize, mmSize);

            // Harita blokları
            for (let x = 0; x < gs.mapSize; x++) {
                for (let y = 0; y < gs.mapSize; y++) {
                    const cell = getMapData(x, y);
                    if (cell === 1) ctx.fillStyle = '#008080';
                    else if (cell === 2) ctx.fillStyle = '#00ffff'; // Ana Ağ Geçidi
                    else if (cell === 3) ctx.fillStyle = '#32cd32'; // Güvenli Veri Odası
                    else continue;
                    
                    ctx.fillRect(mmX + x * cellSize, mmY + y * cellSize, cellSize, cellSize);
                }
            }

            // Otonom Varlıklar
            gs.sprites.forEach((s: any) => {
                ctx.fillStyle = s.color;
                ctx.beginPath();
                ctx.arc(mmX + s.x * cellSize, mmY + s.y * cellSize, 2, 0, Math.PI * 2);
                ctx.fill();
            });

            // Oyuncu konumu
            const pX = mmX + gs.posX * cellSize;
            const pY = mmY + gs.posY * cellSize;

            ctx.fillStyle = '#ff0000';
            ctx.beginPath();
            ctx.arc(pX, pY, 3, 0, Math.PI * 2);
            ctx.fill();

            // Oyunucu bakış yönü
            ctx.strokeStyle = '#ffff00';
            ctx.lineWidth = 1.5;
            ctx.beginPath();
            ctx.moveTo(pX, pY);
            ctx.lineTo(pX + gs.dirX * 12, pY + gs.dirY * 12);
            ctx.stroke();
        };

        let lastTime = performance.now();
        const loop = (time: number) => {
            update();
            draw();
            reqId = requestAnimationFrame(loop);
        };
        
        reqId = requestAnimationFrame(loop);
        
        return () => {
            cancelAnimationFrame(reqId);
            window.removeEventListener('keydown', handleKeyDown);
            window.removeEventListener('keyup', handleKeyUp);
            window.removeEventListener('mousemove', handleMouseMove);
            if (canvas) canvas.removeEventListener('click', handleCanvasClick);
        };
    }, []);

    // Mobil Joystick Durumları
    const [leftJoyPos, setLeftJoyPos] = React.useState({ x: 0, y: 0 });
    const [rightJoyPos, setRightJoyPos] = React.useState({ x: 0, y: 0 });
    const leftJoyRef = useRef({ active: false, startX: 0, startY: 0 });
    const rightJoyRef = useRef({ active: false, startX: 0, startY: 0 });

    const handleLeftDown = (e: React.PointerEvent) => {
        leftJoyRef.current = { active: true, startX: e.clientX, startY: e.clientY };
    };
    const handleLeftMove = (e: React.PointerEvent) => {
        if (!leftJoyRef.current.active) return;
        const dx = e.clientX - leftJoyRef.current.startX;
        const dy = e.clientY - leftJoyRef.current.startY;
        const dist = Math.sqrt(dx*dx + dy*dy);
        const maxDist = 40;
        let nx = dx, ny = dy;
        if (dist > maxDist) {
            nx = (dx / dist) * maxDist;
            ny = (dy / dist) * maxDist;
        }
        setLeftJoyPos({ x: nx, y: ny });
        gameState.current.joyMove = -(ny / maxDist);
    };
    const handleLeftUp = () => {
        leftJoyRef.current.active = false;
        setLeftJoyPos({ x: 0, y: 0 });
        gameState.current.joyMove = 0;
    };

    const handleRightDown = (e: React.PointerEvent) => {
        rightJoyRef.current = { active: true, startX: e.clientX, startY: e.clientY };
    };
    const handleRightMove = (e: React.PointerEvent) => {
        if (!rightJoyRef.current.active) return;
        const dx = e.clientX - rightJoyRef.current.startX;
        const dy = e.clientY - rightJoyRef.current.startY;
        const dist = Math.sqrt(dx*dx + dy*dy);
        const maxDist = 40;
        let nx = dx, ny = dy;
        if (dist > maxDist) {
            nx = (dx / dist) * maxDist;
            ny = (dy / dist) * maxDist;
        }
        setRightJoyPos({ x: nx, y: ny });
        gameState.current.joyTurn = (nx / maxDist);
    };
    const handleRightUp = () => {
        rightJoyRef.current.active = false;
        setRightJoyPos({ x: 0, y: 0 });
        gameState.current.joyTurn = 0;
    };

    return (
        <div className="relative w-full h-full touch-none select-none overflow-hidden">
            <canvas 
                ref={canvasRef} 
                width={800} 
                height={600} 
                className="w-full h-full object-cover retro-pixelated mix-blend-screen"
                style={{ imageRendering: 'pixelated' }}
            />

            {/* Mobile Controls Overlay */}
            <div className="absolute inset-0 pointer-events-none md:hidden flex justify-between items-end p-8 pb-16 z-50">
                {/* Sol Joystick (Hareket) */}
                <div 
                    className="w-32 h-32 bg-white/5 rounded-full border border-white/10 pointer-events-auto relative touch-none opacity-60 backdrop-blur-sm"
                    onPointerDown={handleLeftDown}
                    onPointerMove={handleLeftMove}
                    onPointerUp={handleLeftUp}
                    onPointerCancel={handleLeftUp}
                    onPointerLeave={handleLeftUp}
                >
                    <div 
                        className="absolute w-12 h-12 bg-white/30 rounded-full shadow-[0_0_10px_rgba(255,255,255,0.2)] top-1/2 left-1/2 -ml-6 -mt-6 will-change-transform"
                        style={{ transform: `translate(${leftJoyPos.x}px, ${leftJoyPos.y}px)` }}
                    />
                </div>

                {/* Sağ Joystick (Dönüş) ve Aksiyon */}
                <div className="flex flex-col items-end gap-6">
                    {/* Aksiyon Dümesi - E tuşu yerine */}
                    <button 
                        className="w-14 h-14 bg-[#00ffff]/10 border border-[#00ffff]/50 rounded-full flex items-center justify-center pointer-events-auto active:bg-[#00ffff]/30"
                        onPointerDown={() => { gameState.current.keys.e = true; }}
                        onPointerUp={() => { gameState.current.keys.e = false; }}
                        onPointerLeave={() => { gameState.current.keys.e = false; }}
                        onPointerCancel={() => { gameState.current.keys.e = false; }}
                    >
                        <span className="material-symbols-outlined text-[#00ffff] pointer-events-none">terminal</span>
                    </button>

                    <div 
                        className="w-32 h-32 bg-white/5 rounded-full border border-white/10 pointer-events-auto relative touch-none opacity-60 backdrop-blur-sm"
                        onPointerDown={handleRightDown}
                        onPointerMove={handleRightMove}
                        onPointerUp={handleRightUp}
                        onPointerCancel={handleRightUp}
                        onPointerLeave={handleRightUp}
                    >
                        <div 
                            className="absolute w-12 h-12 bg-white/30 rounded-full shadow-[0_0_10px_rgba(255,255,255,0.2)] top-1/2 left-1/2 -ml-6 -mt-6 will-change-transform"
                            style={{ transform: `translate(${rightJoyPos.x}px, ${rightJoyPos.y}px)` }}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}
